#!/usr/bin/env python3
"""
CI/CD dependency installation script for automated deployment pipeline.
Installs all requirements securely with hash verification.
"""

import subprocess
import sys
import os


def install_requirements():
    """Install requirements from requirements.txt with security best practices."""
    
    requirements_file = "requirements.txt"
    
    # Verify requirements file exists
    if not os.path.isfile(requirements_file):
        print(f"ERROR: {requirements_file} not found.")
        sys.exit(1)
    
    # Verify requirements file is not a symlink (prevent symlink attacks)
    if os.path.islink(requirements_file):
        print(f"ERROR: {requirements_file} is a symlink. This is not allowed for security reasons.")
        sys.exit(1)
    
    # Build the pip install command with security best practices
    cmd = [
        sys.executable, "-m", "pip", "install",
        "-r", requirements_file,
        "--require-hashes",       # Enforce hash verification for supply chain security
        "--no-deps",              # Don't install unlisted transitive dependencies
        "--only-binary", ":all:", # Only install pre-built wheels (avoid arbitrary code execution from setup.py)
    ]
    
    # Note: --upgrade is intentionally omitted. In CI/CD, dependencies should be
    # pinned to exact versions in requirements.txt with hashes. Using --upgrade
    # would attempt to fetch newer versions, which:
    #   1. Is incompatible with --require-hashes (hashes won't match)
    #   2. Introduces non-deterministic builds
    #   3. Could pull in compromised newer versions (supply chain attack)
    
    print("Installing dependencies with hash verification enabled...")
    print(f"Running: {' '.join(cmd)}")
    
    try:
        result = subprocess.run(
            cmd,
            check=True,
            capture_output=True,
            text=True,
            timeout=600,  # 10-minute timeout to prevent hanging builds
        )
        print(result.stdout)
        print("Dependencies installed successfully.")
    except subprocess.CalledProcessError as e:
        print(f"ERROR: pip install failed with return code {e.returncode}")
        print(f"STDOUT: {e.stdout}")
        print(f"STDERR: {e.stderr}")
        print(
            "\nIf hash verification failed, regenerate your requirements.txt with hashes using:\n"
            "  pip-compile --generate-hashes requirements.in -o requirements.txt\n"
            "or:\n"
            "  pip hash <package-file>.whl\n"
        )
        sys.exit(1)
    except subprocess.TimeoutExpired:
        print("ERROR: pip install timed out after 600 seconds.")
        sys.exit(1)


def verify_pip_version():
    """Ensure pip itself is reasonably up to date for security fixes."""
    try:
        result = subprocess.run(
            [sys.executable, "-m", "pip", "--version"],
            check=True,
            capture_output=True,
            text=True,
            timeout=30,
        )
        print(f"Using: {result.stdout.strip()}")
    except (subprocess.CalledProcessError, subprocess.TimeoutExpired) as e:
        print(f"WARNING: Could not verify pip version: {e}")


